#include<iostream>
#define MAX 10000
using namespace std;
char a[MAX + 1] = { 1 };
int i, j, up, n, tem;
void GetN()
{
	cin >> n;
}

void XX()
{
	for (i = 2; i <= n; i++)
	{
		for (up = 0, j = 0; j <= MAX; j++)
		{
			tem = a[j] * i + up;
			up = tem / 10;
			a[j] = tem % 10;

		}

	}
}

void display()
{
	for (i = MAX; i >= 0; i--) 
		if (a[i] != 0)
			for (i; i >= 0; i--)
				cout << (int)a[i];
}

int main()
{
	GetN();
	XX();
	display();
}

