大数加法：

#include<iostream>
#include<cstring>
#define MAX 1000
using namespace std;
int a[MAX+1]={0},b[MAX+1]={0};
int i,up,tem;
void InPutA ()
{
    char buffer[MAX+1]={0};
    cin>>buffer;
    for(tem=0,i=strlen(buffer)-1;i>=0;i--)
    {
        a[tem++]=buffer[i]-'0';
    }
}

void InPutB()
{
    char buffer[MAX+1]={0};
    cin>>buffer;
    for(tem=0,i=strlen(buffer)-1;i>=0;i--)
    {
        b[tem++]=buffer[i]-'0';
    }
}

void Add()
{
    for(up=0,i=0;i<MAX;i++)
    {
        tem=a[i]+b[i]+up;
        a[i]=tem%10;
        up=tem/10;
    }
}

void DisPlay()
{
        for(i=MAX;i>=0;i--)
        {
                if(a[i]!=0)
                {
                        for(i;i>=0;i--)
                        {
                                cout<<a[i];
                        }
                }
        }
}

int main()
{
    InPutA();
    InPutB();
    Add();
    DisPlay();
}
